        { q: "Una distancia puede ser negativa si la correlación es negativa.", a: false, why: "La distancia nunca debe ser negativa; por eso d = 1 - |r| usa valor absoluto." },
        { q: "Distancia baja significa perfiles similares según la métrica elegida.", a: true, why: "Cerca/lejos siempre depende de la métrica." }
