COPY.en = COPY.es;
COPY.fa = COPY.es;
function getCopy(lang = "es") { return COPY[lang] || COPY.es; }

function parseNumbers(text) { return String(text).split(/[,;\s]+/).map((x) => Number(x.trim())).filter(Number.isFinite); }
function mean(xs) { return xs.length ? xs.reduce((a, b) => a + b, 0) / xs.length : NaN; }
function sd(xs) { const m = mean(xs); if (xs.length < 2 || !Number.isFinite(m)) return NaN; return Math.sqrt(xs.reduce((a, x) => a + (x - m) ** 2, 0) / (xs.length - 1)); }
function fmt(x, digits = 2) { return Number.isFinite(x) ? x.toFixed(digits).replace(/\.00$/, "") : "—"; }

function Navigation({ ui, isDone, toggle, position = "top" }) { return <nav className={`${position === "bottom" ? "mt-10" : "mb-6"} rounded-[2rem] border border-stone-200 bg-white/85 p-3 shadow-sm`} aria-label="Lesson navigation"><div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between"><a href="#/lesson/m1-deg-ii" className="rounded-full border border-stone-200 bg-stone-50 px-4 py-2 text-sm font-black text-stone-700 transition hover:-translate-y-0.5 hover:bg-white hover:shadow-md">← {ui.previous}: {ui.previousTitle}</a><div className="flex flex-col items-stretch gap-2 sm:flex-row sm:items-center sm:justify-center"><a href="#/" className="rounded-full border border-stone-200 bg-white px-4 py-2 text-center text-xs font-black uppercase tracking-[0.2em] text-stone-500 transition hover:bg-stone-50">{ui.current} · {ui.dashboard}</a><button onClick={toggle} className={`rounded-full px-4 py-2 text-sm font-black shadow-sm transition hover:-translate-y-0.5 ${isDone ? "bg-emerald-600 text-white" : "bg-stone-950 text-white"}`}>{isDone ? ui.done : ui.mark}</button></div><a href="#/lesson/m1-samples-genes-ii" className="rounded-full bg-stone-950 px-4 py-2 text-sm font-black text-white shadow-sm transition hover:-translate-y-0.5 hover:bg-red-700 hover:shadow-md">{ui.next}: {ui.nextTitle} →</a></div></nav>; }
function HeroEyebrow({ children }) { return <div className="inline-flex rounded-full border border-red-200 bg-red-50 px-4 py-2 text-xs font-black uppercase tracking-[0.22em] text-red-700">{children}</div>; }
function Pill({ children, tone = "stone" }) { const cls = tone === "red" ? "border-red-200 bg-red-50 text-red-700" : "border-stone-200 bg-white/80 text-stone-700"; return <span className={`rounded-full border px-3 py-1 text-xs font-black uppercase tracking-[0.16em] ${cls}`}>{children}</span>; }
function StatCard({ label, value, tone = "stone" }) { return <div className={`rounded-2xl border p-4 ${tone === "red" ? "border-red-200 bg-red-50" : "border-stone-200 bg-stone-50"}`}><div className="text-xs font-black uppercase tracking-[0.2em] text-stone-500">{label}</div><div className="mt-2 text-2xl font-black text-stone-950">{value}</div></div>; }
function ResourceLinks({ ui }) { const linkBase = "rounded-2xl border px-4 py-3 text-sm font-black transition hover:-translate-y-0.5 hover:shadow-sm"; return <div className="mt-4 rounded-3xl border border-stone-200 bg-stone-50 p-4"><div className="mb-3 text-xs font-black uppercase tracking-[0.18em] text-stone-500">{ui.resources}</div><div className="grid gap-2 sm:grid-cols-3"><a href={SLIDES_URL} target="_blank" rel="noreferrer" className={`${linkBase} border-red-200 bg-red-50 text-red-800 hover:bg-white`}>{ui.slides}</a><a href={TRANSCRIPT_URL} target="_blank" rel="noreferrer" className={`${linkBase} border-stone-200 bg-white text-stone-800 hover:bg-stone-50`}>{ui.transcript}</a><a href={RECORDING_URL} target="_blank" rel="noreferrer" className={`${linkBase} border-stone-800 bg-stone-950 text-white hover:bg-red-700`}>{ui.recording}</a></div></div>; }
function SectionHeader({ eyebrow, title, children }) { return <div className="mb-6"><div className="text-xs font-black uppercase tracking-[0.22em] text-red-700">{eyebrow}</div><h2 className="mt-2 text-3xl font-black tracking-tight text-stone-950 md:text-4xl">{title}</h2>{children ? <p className="mt-3 max-w-4xl text-base font-semibold leading-7 text-stone-600">{children}</p> : null}</div>; }
function NoteBox({ ui, type, children }) { const isExam = type === "exam"; return <div className={`mt-4 rounded-2xl border p-4 ${isExam ? "border-red-200 bg-red-50" : "border-amber-200 bg-amber-50"}`}><div className={`text-xs font-black uppercase tracking-[0.2em] ${isExam ? "text-red-700" : "text-amber-800"}`}>{isExam ? ui.exam : ui.professor}</div><div className="mt-2 text-sm font-bold leading-6 text-stone-800">{children}</div></div>; }
function ExamWatch({ ui, data }) { if (!data) return null; const model = data.model || data.answer || ""; return <details className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4"><summary className="cursor-pointer text-sm font-black text-red-800">{ui.exam}: {data.q}</summary><div className="mt-4 rounded-2xl border border-red-100 bg-white p-4"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{ui.include}</div><ul className="mt-3 space-y-2 text-sm font-semibold leading-6 text-stone-700">{data.include.map((x) => <li key={x}>• {x}</li>)}</ul><div className="mt-4 rounded-2xl border border-amber-200 bg-amber-50 p-4"><div className="text-xs font-black uppercase tracking-[0.18em] text-amber-800">{ui.trap}</div><p className="mt-2 text-sm font-bold leading-6 text-amber-950">{data.trap}</p></div>{model ? <div className="mt-4 rounded-2xl border border-stone-200 bg-stone-50 p-4"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{ui.model}</div><p className="mt-2 text-sm font-bold leading-7 text-stone-800">{model}</p></div> : null}</div></details>; }
function SlideCard({ ui, item, openZoom, spanFull }) { const figure = IMG[item.img]; if (!figure) return null; return <article className={`overflow-hidden rounded-[2rem] border border-stone-200 bg-stone-50 shadow-sm ${spanFull ? "md:col-span-2" : ""}`}><button onClick={() => openZoom({ ...figure, title: item.title })} className="group block w-full border-b border-stone-200 bg-white p-3 text-left"><div className={`${spanFull ? "aspect-[16/9]" : "aspect-[4/3]"} overflow-hidden rounded-2xl bg-white`}><img src={figure.src} alt={item.title} loading="lazy" className="h-full w-full object-contain transition duration-300 group-hover:scale-[1.02]" /></div></button><div className="p-5"><div className="flex flex-wrap items-center gap-2"><Pill tone="red">{ui.slide} {figure.slide}</Pill><span className="text-xs font-black uppercase tracking-[0.16em] text-stone-400">{ui.zoom}</span></div><h3 className="mt-3 text-xl font-black text-stone-950">{item.title}</h3><p className="mt-2 text-sm font-semibold leading-6 text-stone-600">{item.body}</p>{(item.professor || item.emphasis) ? <NoteBox ui={ui}>{item.professor || item.emphasis}</NoteBox> : null}<ExamWatch ui={ui} data={item.exam}/></div></article>; }
function SlideGrid({ ui, slides, openZoom }) { return <div className="grid gap-5 md:grid-cols-2">{slides.map((item, idx) => <SlideCard key={`${item.img}-${idx}`} ui={ui} item={item} openZoom={openZoom} spanFull={slides.length % 2 === 1 && idx === slides.length - 1}/>)}</div>; }
function ZoomModal({ ui, zoom, setZoom }) { if (!zoom) return null; return <div className="fixed inset-0 z-50 flex items-center justify-center bg-stone-950/80 p-4" onClick={() => setZoom(null)}><div className="max-h-[92vh] w-[min(1100px,96vw)] overflow-auto rounded-[2rem] bg-white p-4 shadow-2xl" onClick={(e) => e.stopPropagation()}><div className="mb-3 flex items-center justify-between gap-3"><div><Pill tone="red">{ui.slide} {zoom.slide}</Pill><h3 className="mt-2 text-xl font-black text-stone-950">{zoom.title}</h3></div><button onClick={() => setZoom(null)} className="rounded-full bg-stone-950 px-4 py-2 text-sm font-black text-white">{ui.close}</button></div><img src={zoom.src} alt={zoom.title} className="max-h-[78vh] w-full rounded-2xl object-contain" /></div></div>; }
function InteractiveShell({ title, intro, children }) { return <div className="mt-6 rounded-[2rem] border border-stone-200 bg-stone-50 p-5"><h3 className="text-2xl font-black text-stone-950">{title}</h3><p className="mt-2 text-sm font-semibold leading-6 text-stone-600">{intro}</p><div className="mt-5">{children}</div></div>; }
function ResultPill({ label, value, tone = "stone" }) { return <div className={`rounded-2xl border p-4 ${tone === "red" ? "border-red-200 bg-red-50" : "border-stone-200 bg-white"}`}><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{label}</div><div className="mt-1 text-xl font-black text-stone-950">{value}</div></div>; }
function DataBox({ label, value, onChange, rows = 3 }) { return <label className="text-sm font-black text-stone-700">{label}<textarea value={value} rows={rows} onChange={(e) => onChange(e.target.value)} className="mt-2 min-h-[90px] w-full rounded-2xl border border-stone-200 bg-white px-4 py-3 font-mono text-sm leading-6 outline-none focus:border-red-300"/></label>; }

function DirectionLab({ lab }) { const [answers, setAnswers] = useState({}); return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-3">{lab.items.map((item, i) => { const ok = answers[i] === item.a; return <div key={item.q} className="rounded-2xl border border-stone-200 bg-white p-4"><p className="font-black leading-6 text-stone-900">{item.q}</p><div className="mt-3 grid grid-cols-2 gap-2"><button onClick={() => setAnswers({ ...answers, [i]: "genes" })} className={`rounded-xl border px-3 py-2 text-sm font-black ${answers[i] === "genes" ? (ok ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-stone-50"}`}>{lab.genes}</button><button onClick={() => setAnswers({ ...answers, [i]: "samples" })} className={`rounded-xl border px-3 py-2 text-sm font-black ${answers[i] === "samples" ? (ok ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-stone-50"}`}>{lab.samples}</button></div>{answers[i] ? <p className="mt-3 text-sm font-bold leading-6 text-stone-600">{item.why}</p> : null}</div>; })}</div></InteractiveShell>; }
function DistanceLab({ lab }) { const [answers, setAnswers] = useState({}); return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-3">{lab.items.map((item, i) => { const ok = answers[i] === item.a; return <div key={item.q} className="rounded-2xl border border-stone-200 bg-white p-4"><p className="font-black leading-6 text-stone-900">{item.q}</p><div className="mt-3 grid grid-cols-2 gap-2"><button onClick={() => setAnswers({ ...answers, [i]: true })} className={`rounded-xl border px-3 py-2 text-sm font-black ${answers[i] === true ? (ok ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-stone-50"}`}>{lab.trueLabel}</button><button onClick={() => setAnswers({ ...answers, [i]: false })} className={`rounded-xl border px-3 py-2 text-sm font-black ${answers[i] === false ? (ok ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-stone-50"}`}>{lab.falseLabel}</button></div>{answers[i] !== undefined ? <p className="mt-3 text-sm font-bold leading-6 text-stone-600">{item.why}</p> : null}</div>; })}</div></InteractiveShell>; }
function PearsonLab({ lab }) { const [r, setR] = useState(0.97); const d = 1 - Math.abs(r); const abs = Math.abs(r); const meaning = abs > 0.8 ? "Relación fuerte; distancia baja." : abs > 0.5 ? "Relación moderada; revisa el plot." : "Relación débil o nula; distancia alta."; return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-[1fr_1fr_1fr]"><label className="rounded-2xl border border-stone-200 bg-white p-4"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{lab.r}</div><input type="range" min="-1" max="1" step="0.01" value={r} onChange={(e) => setR(Number(e.target.value))} className="mt-4 w-full"/><div className="mt-2 text-2xl font-black text-stone-950">{fmt(r, 2)}</div></label><ResultPill label={lab.d} value={fmt(d, 2)} tone="red"/><div className="rounded-2xl border border-stone-200 bg-white p-4"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{lab.meaning}</div><p className="mt-2 text-sm font-bold leading-6 text-stone-700">{meaning}</p></div></div></InteractiveShell>; }
function MetricLab({ lab }) { const [answers, setAnswers] = useState({}); return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-3">{lab.items.map((item, i) => <div key={item.q} className="rounded-2xl border border-stone-200 bg-white p-4"><p className="font-black leading-6 text-stone-900">{item.q}</p><div className="mt-3 grid gap-2">{item.options.map((op) => { const chosen = answers[i] === op; const ok = op === item.a; return <button key={op} onClick={() => setAnswers({ ...answers, [i]: op })} className={`rounded-xl border px-3 py-2 text-left text-sm font-black ${chosen ? (ok ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-stone-50"}`}>{op}</button>; })}</div>{answers[i] ? <p className="mt-3 text-sm font-bold leading-6 text-stone-600">{item.why}</p> : null}</div>)}</div></InteractiveShell>; }
function MdsLab({ lab }) { const [metric, setMetric] = useState("euclidean"); const points = metric === "euclidean" ? [[15,80,"0.5h"],[30,22,"2h"],[58,14,"5h"],[78,32,"7h"],[82,62,"9h"],[90,86,"11h"]] : [[12,82,"0.5h"],[26,18,"2h"],[62,25,"5h"],[75,70,"7h"],[81,68,"9h"],[88,78,"11h"]]; return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 lg:grid-cols-[0.75fr_1.25fr]"><div className="grid gap-2"><button onClick={() => setMetric("euclidean")} className={`rounded-2xl border px-4 py-3 text-left font-black ${metric === "euclidean" ? "border-red-200 bg-red-50 text-red-800" : "border-stone-200 bg-white"}`}>{lab.euclidean}</button><button onClick={() => setMetric("correlation")} className={`rounded-2xl border px-4 py-3 text-left font-black ${metric === "correlation" ? "border-red-200 bg-red-50 text-red-800" : "border-stone-200 bg-white"}`}>{lab.correlation}</button><p className="rounded-2xl bg-stone-950 p-4 text-sm font-black leading-6 text-white">{lab.note}</p></div><svg viewBox="0 0 100 100" className="min-h-[260px] rounded-[1.5rem] border border-stone-200 bg-white p-3"><line x1="8" y1="92" x2="95" y2="92" stroke="#d6d3d1"/><line x1="8" y1="8" x2="8" y2="92" stroke="#d6d3d1"/>{points.map(([x,y,label]) => <g key={label}><circle cx={x} cy={y} r="3.5" fill="#dc2626"/><text x={x + 3} y={y - 3} fontSize="5" fontWeight="700" fill="#292524">{label}</text></g>)}</svg></div></InteractiveShell>; }
function LinkageLab({ lab }) { const [method, setMethod] = useState("average"); const info = lab.methods[method]; return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-[0.8fr_1.2fr]"><div className="grid gap-2">{Object.entries(lab.methods).map(([key, item]) => <button key={key} onClick={() => setMethod(key)} className={`rounded-2xl border px-4 py-3 text-left text-sm font-black ${method === key ? "border-red-200 bg-red-50 text-red-800" : "border-stone-200 bg-white text-stone-700"}`}>{item.name}</button>)}</div><div className="rounded-[1.5rem] bg-stone-950 p-6 text-white"><div className="text-xs font-black uppercase tracking-[0.18em] text-red-200">{info.name}</div><p className="mt-3 text-xl font-black leading-8">{info.text}</p></div></div></InteractiveShell>; }
function BootstrapLab({ lab }) { const [total, setTotal] = useState(1000); const [recovered, setRecovered] = useState(950); const support = Math.max(0, Math.min(100, (Number(recovered) / Math.max(1, Number(total))) * 100)); const verdict = support >= 95 ? lab.strong : support >= 80 ? lab.good : support >= 70 ? lab.moderate : lab.weak; return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-4"><label className="text-sm font-black text-stone-700">{lab.total}<input type="number" value={total} onChange={(e) => setTotal(Number(e.target.value))} className="mt-2 w-full rounded-2xl border border-stone-200 bg-white px-4 py-3 font-black outline-none focus:border-red-300"/></label><label className="text-sm font-black text-stone-700">{lab.recovered}<input type="number" value={recovered} onChange={(e) => setRecovered(Number(e.target.value))} className="mt-2 w-full rounded-2xl border border-stone-200 bg-white px-4 py-3 font-black outline-none focus:border-red-300"/></label><ResultPill label={lab.support} value={`${fmt(support, 1)}%`} tone="red"/><ResultPill label={lab.verdict} value={verdict}/></div></InteractiveShell>; }
function ZScoreLab({ lab }) { const [values, setValues] = useState("10, 20, 30"); const xs = parseNumbers(values); const m = mean(xs); const s = sd(xs); const zs = xs.map((x) => Number.isFinite(s) && s > 0 ? (x - m) / s : NaN); return <InteractiveShell title={lab.title} intro={lab.intro}><div className="grid gap-4 md:grid-cols-[1fr_1fr]"><DataBox label={lab.values} value={values} onChange={setValues}/><div className="grid gap-3 sm:grid-cols-3"><ResultPill label={lab.mean} value={fmt(m, 2)}/><ResultPill label={lab.sd} value={fmt(s, 2)}/><ResultPill label={lab.z} value={zs.map((z) => fmt(z, 2)).join(", ")} tone="red"/></div></div></InteractiveShell>; }
function renderLab(name, copy) { const lab = copy.labs[name]; if (!lab) return null; if (name === "matrix") return <DirectionLab lab={lab}/>; if (name === "distance") return <DistanceLab lab={lab}/>; if (name === "pearson") return <PearsonLab lab={lab}/>; if (name === "metric") return <MetricLab lab={lab}/>; if (name === "mds") return <MdsLab lab={lab}/>; if (name === "linkage") return <LinkageLab lab={lab}/>; if (name === "bootstrap") return <BootstrapLab lab={lab}/>; if (name === "zscore") return <ZScoreLab lab={lab}/>; return null; }
function Quiz({ ui, copy }) { const items = copy.labs.quiz.items; const [answers, setAnswers] = useState({}); const score = items.reduce((acc, item, i) => acc + (answers[i] === item.answer ? 1 : 0), 0); return <section className="mt-10 rounded-[2rem] border border-stone-200 bg-white p-6 shadow-sm"><SectionHeader eyebrow={ui.checkpoint} title={copy.labs.quiz.title}>{copy.labs.quiz.score}: {score}/{items.length}</SectionHeader><div className="grid gap-4 md:grid-cols-2">{items.map((item, i) => <div key={item.q} className="rounded-2xl border border-stone-200 bg-stone-50 p-4"><p className="font-black text-stone-950">{i + 1}. {item.q}</p><div className="mt-3 grid gap-2">{item.options.map((option, j) => <button key={option} onClick={() => setAnswers({ ...answers, [i]: j })} className={`rounded-xl border px-3 py-2 text-left text-sm font-bold ${answers[i] === j ? (j === item.answer ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-white text-stone-700"}`}>{option}</button>)}</div></div>)}</div></section>; }
function WrittenTrainer({ ui, copy }) { const lab = copy.labs.written; const [text, setText] = useState(""); const wc = text.trim() ? text.trim().split(/\s+/).length : 0; return <section className="mt-10 rounded-[2rem] border border-stone-200 bg-white p-6 shadow-sm"><SectionHeader eyebrow={ui.exam} title={lab.title}>{lab.prompt}</SectionHeader><textarea value={text} onChange={(e) => setText(e.target.value)} placeholder={lab.placeholder} className="min-h-[230px] w-full rounded-[1.5rem] border border-stone-200 bg-stone-50 p-4 text-sm font-semibold leading-6 outline-none focus:border-red-300"/><div className="mt-2 text-xs font-black uppercase tracking-[0.18em] text-stone-500">{wc} {ui.words}</div><details className="mt-4 rounded-[1.5rem] border border-stone-200 bg-stone-50 p-4"><summary className="cursor-pointer font-black text-red-800">{ui.model}</summary><p className="mt-3 text-sm font-semibold leading-7 text-stone-700">{lab.model}</p></details></section>; }

export default function DRDLesson11({ lang = "es", isDone = false, toggle = () => {} }) {
  const ui = getUi(lang);
  const copy = getCopy(lang);
  const [zoom, setZoom] = useState(null);
  const sections = useMemo(() => copy.sections, [copy]);
  return <main className="mx-auto w-[min(1180px,calc(100%-24px))] pb-16 pt-8 md:pt-12 text-stone-900"><Navigation ui={ui} isDone={isDone} toggle={toggle}/>
    <section className="overflow-hidden rounded-[2.5rem] border border-stone-200 bg-[#fffaf0]/92 shadow-xl shadow-stone-900/5"><div className="grid gap-0 lg:grid-cols-[1.05fr_0.95fr]"><div className="p-7 md:p-10 lg:p-12"><HeroEyebrow>{ui.heroEyebrow}</HeroEyebrow><h1 className="mt-5 max-w-4xl text-4xl font-black leading-[0.96] tracking-tight text-stone-950 md:text-6xl">{ui.heroTitle}</h1><p className="mt-6 max-w-3xl text-lg leading-8 text-stone-700">{ui.heroSubtitle}</p><div className="mt-6 flex flex-wrap gap-2">{ui.tags.map((tag) => <Pill key={tag} tone={tag === "MDS" || tag === "clustering" || tag === "heatmap" ? "red" : "stone"}>{tag}</Pill>)}</div></div><div className="border-t border-stone-200 bg-white/70 p-5 lg:border-l lg:border-t-0"><div className="h-full rounded-[2rem] border border-stone-200 bg-white p-5 shadow-inner"><div className="grid grid-cols-2 gap-3"><StatCard label={ui.module} value="1" tone="red"/><StatCard label={ui.writtenExam} value="4Q"/><StatCard label={ui.answerLines} value="10–12"/><StatCard label={ui.core} value="MDS/HC" tone="red"/></div><div className="mt-5 rounded-3xl bg-stone-950 p-5 text-white"><div className="text-xs font-black uppercase tracking-[0.18em] text-red-200">{ui.bigIdea}</div><p className="mt-2 text-lg font-bold leading-7">{ui.bigIdeaText}</p></div><ResourceLinks ui={ui}/></div></div></div></section>
    {sections.map((section, idx) => <section key={section.title} className="mt-10 rounded-[2.5rem] border border-stone-200 bg-white/80 p-6 shadow-sm md:p-8"><SectionHeader eyebrow={`Part ${idx + 1}`} title={section.title}>{section.intro}</SectionHeader><SlideGrid ui={ui} slides={section.slides} openZoom={setZoom}/>{renderLab(section.lab, copy)}</section>)}
    <Quiz ui={ui} copy={copy}/><WrittenTrainer ui={ui} copy={copy}/><Navigation ui={ui} isDone={isDone} toggle={toggle} position="bottom"/><ZoomModal ui={ui} zoom={zoom} setZoom={setZoom}/>
  </main>;
}
